        <label\r\n                                                                for=\"cash\"\r\n                                                                class=\"radio-tile-label2\"\r\n                                                                >Imprimir</label\r\n                                                            >\r\n                                                        </div>\r\n                                                    </div>\r\n                                                    <div\r\n                                                        class=\"input-container2 border rounded-sm col-lg-3\"\r\n                                                    >\r\n                                                        <input\r\n                                                            id=\"noimprimir\"\r\n                                                            v-model=\"printerOn\"\r\n                                                            class=\"radio-button2\"\r\n                                                            type=\"radio\"\r\n                                                            name=\"noimprimir\"\r\n                                                            value=\"0\"\r\n                                                        />\r\n                                                        <div\r\n                                                            class=\"radio-tile2\"\r\n                                                        >\r\n                                                            <div\r\n                                                                class=\"icon bike-icon\"\r\n                                                            >\r\n                                                                <i\r\n                                                                    class=\"fa fa-print\"\r\n                                                                ></i>\r\n                                                            </div>\r\n                                                            <label\r\n                                                                for=\"Tarjeta\"\r\n                                                                class=\"radio-tile-label2\"\r\n                                                                >No\r\n                                                                Imprimir</label\r\n                                                            >\r\n                                                        </div>\r\n                                                    </div>\r\n                                                </div>\r\n                                            </div>\r\n                                        </div>\r\n\r\n                                        <div class=\"row\">\r\n                                            <div\r\n                                                class=\"col-lg-8 d-flex flex-row align-items-end\"\r\n                                            ></div>\r\n                                            <div\r\n                                                class=\"d-flex flex-column\"\r\n                                            ></div>\r\n                                        </div>\r\n                                        <div\r\n                                            class=\"row d-flex justify-content-start\"\r\n                                        >\r\n                                            <table\r\n                                                class=\"table\"\r\n                                                v-if=\"\r\n                                                    currentPayments.length != 0\r\n                                                \"\r\n                                            >\r\n                                                <thead>\r\n                                                    <tr>\r\n                                                        <th\r\n                                                            colspan=\"4\"\r\n                                                            class=\"text-left\"\r\n                                                        >\r\n                                                            Pagos\r\n                                                        </th>\r\n                                                    </tr>\r\n                                                </thead>\r\n                                                <tbody>\r\n                                                    <tr\r\n                                                        v-for=\"(paymnt,\r\n                                                        idx) in currentPayments\"\r\n                                                        :key=\"idx\"\r\n                                                    >\r\n                                                        <td>{{ idx + 1 }}</td>\r\n                                                        <td>\r\n                                                            {{ paymnt.method }}\r\n                                                        </td>\r\n                                                        <td>\r\n                                                            <strong>{{\r\n                                                                paymnt.amount\r\n                                                            }}</strong>\r\n                                                        </td>\r\n                                                        <td>\r\n                                                            <label\r\n                                                                for=\"\"\r\n                                                                role=\"button\"\r\n                                                                @click=\"\r\n                                                                    removePayment(\r\n                                                                        paymnt.id\r\n                                                                    )\r\n                                                                \"\r\n                                                                class=\"text-danger\"\r\n                                                            >\r\n                                                                <i\r\n                                                                    class=\"fa fa-trash\"\r\n                                                                ></i\r\n                                                            ></label>\r\n                                                        </td>\r\n                                                    </tr>\r\n                                                </tbody>\r\n                                            </table>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"col-lg-12\">\r\n                            <div class=\"mb-2\">\r\n                                <div class=\"card bg-light\">\r\n                                    <div class=\"row\">\r\n                                        <div\r\n                                            class=\"col-xl-4 d-flex flex-column justify-content-center align-items-start\"\r\n                                            :class=\"{\r\n                                                'has-danger':\r\n                                                    form.difference < 0\r\n                                            }\"\r\n                                        >\r\n                                            <label\r\n                                                v-if=\"credit > 0\"\r\n                                                class=\"control-label h1\r\n                                                text-success\r\n                                                \"\r\n                                                >Crédito:\r\n                                            </label>\r\n                                            <span\r\n                                                v-if=\"credit > 0\"\r\n                                                class=\"\r\n                                                d-block\r\n                          control-label\r\n                          font-weight-semibold\r\n                          text-center\r\n                          text-success\r\n                          h3\r\n                        \"\r\n                                            >\r\n                                                S/ {{ \" \" + credit }}\r\n                                            </span>\r\n                                            <label class=\"control-label h1\"\r\n                                                >Total a cobrar:\r\n                                            </label>\r\n                                            <span\r\n                                                class=\"\r\n                                                d-block\r\n                          control-label\r\n                          font-weight-semibold\r\n                          text-center\r\n                          h3\r\n                        \"\r\n                                            >\r\n                                                S/ {{ \" \" + form.total }}\r\n                                            </span>\r\n                                        </div>\r\n                                        <div\r\n                                            class=\"col-xl-8\"\r\n                                            v-if=\"\r\n                                                form_payment.payment_method_type_id ==\r\n                                                    '01'\r\n                                            \"\r\n                                        >\r\n                                            <div\r\n                                                class=\"\r\n                          btn-group btn-group-square\r\n                          m-0\r\n                          flex-wrap\r\n                          justify-content-around\r\n                        \"\r\n                                                role=\"group\"\r\n                                                style=\"padding-top: 12px\"\r\n                                            >\r\n                                                <label class=\"control-label\"\r\n                                                    >Ingrese monto</label\r\n                                                >\r\n                                                <div class=\"row col-12\">\r\n                                                    <div\r\n                                                        class=\"col-2 col-md-2 col-xl-2\"\r\n                                                    >\r\n                                                        <button\r\n                                                            class=\"btn btn-outline-primary btn_responsive m-2\"\r\n                                                            @click=\"\r\n                                                                setAmountCash(\r\n                                                                    10\r\n                                                                )\r\n                                                            \"\r\n                                                        >\r\n                                                            {{\r\n                                                                currencyTypeActive.symbol\r\n                                                            }}10\r\n                                                        </button>\r\n                                                    </div>\r\n                                                    <div\r\n                                                        class=\"col-2 col-md-2 col-xl-2\"\r\n                                                    >\r\n                                                        <button\r\n                                                            class=\"btn btn-outline-primary btn_responsive m-2\"\r\n                                                            @click=\"\r\n                                                                setAmountCash(\r\n                                                                    20\r\n                                                                )\r\n                                                            \"\r\n                                                        >\r\n                                                            {{\r\n                                                                currencyTypeActive.symbol\r\n                                                            }}20\r\n                                                        </button>\r\n                                                    </div>\r\n                                                    <div\r\n                                                        class=\"col-2 col-md-2 col-xl-2\"\r\n                                                    >\r\n                                                        <button\r\n                                                            class=\"btn btn-outline-primary btn_responsive m-2\"\r\n                                                            @click=\"\r\n                                                                setAmountCash(\r\n                                                                    50\r\n                                                                )\r\n                                                            \"\r\n                                                        >\r\n                                                            {{\r\n                                                                currencyTypeActive.symbol\r\n                                                            }}50\r\n                                                        </button>\r\n                                                    </div>\r\n                                                    <div\r\n                                                        class=\"col-2 col-md-2 col-xl-2\"\r\n                                                    >\r\n                                                        <button\r\n                                                            class=\"btn btn-outline-primary btn_responsive m-2\"\r\n                                                            @click=\"\r\n                                                                setAmountCash(\r\n                                                                    100\r\n                                                                )\r\n                                                            \"\r\n                                                        >\r\n                                                            {{\r\n                                                                currencyTypeActive.symbol\r\n                                                            }}100\r\n                                                        </button>\r\n                                                    </div>\r\n                                                    <div\r\n                                                        class=\"col-2 col-md-2 col-xl-2\"\r\n                                                    >\r\n                                                        <button\r\n                                                            class=\"btn btn-outline-primary btn_responsive m-2\"\r\n                                                            @click=\"\r\n                                                                setAmountCash(\r\n                                                                    200\r\n                                                                )\r\n                                                            \"\r\n                                                        >\r\n                                                            {{\r\n                                                                currencyTypeActive.symbol\r\n                                                            }}200\r\n                                                        </button>\r\n                                                    </div>\r\n                                                </div>\r\n                                                <div\r\n                                                    class=\"row col-xl-12 col-12\"\r\n                                                >\r\n                                                    <div class=\"col-xl-6 col-3\">\r\n                                                        <el-input\r\n                                                            id=\"inputTotal\"\r\n                                                            ref=\"enter_amount\"\r\n                                                            :disabled=\"\r\n                                                                form.total == 0\r\n                                                            \"\r\n                                                            v-model=\"\r\n                                                                form.enter_amount\r\n                                                            \"\r\n                                                            @blur=\"diferen()\"\r\n                                                            @input=\"\r\n                                                                enterAmount()\r\n                                                            \"\r\n                                                            @keyup.enter.native=\"\r\n                                                                sendPayment();\r\n                                                                inputAmount(\r\n                                                                    form.enter_amount\r\n                                                                );\r\n                                                            \"\r\n                                                        >\r\n                                                            <template\r\n                                                                slot=\"prepend\"\r\n                                                                >{{\r\n                                                                    currencyTypeActive.symbol\r\n                                                                }}\r\n                                                            </template>\r\n                                                        </el-input>\r\n                                                    </div>\r\n                                                    <div class=\"col-xl-2 col-2\">\r\n                                                        <el-button\r\n                                                            type=\"primary\"\r\n                                                            @click=\"addPayment\"\r\n                                                            >Agregar</el-button\r\n                                                        >\r\n                                                    </div>\r\n                                                    <!-- <div\r\n                                                