              <div class=\\\"row\\\">\\r\\n                                        <div\\r\\n                                            class=\\\"col-md-12 col-12 d-flex justify-content-end\\\"\\r\\n                                        >\\r\\n                                            <div\\r\\n                                                class=\\\"form-group d-flex flex-row align-items-end\\\"\\r\\n                                                :class=\\\"{\\r\\n                                                    'has-danger':\\r\\n                                                        form.difference < 0\\r\\n                                                }\\\"\\r\\n                                            >\\r\\n                                                <div>\\r\\n                                                    <el-checkbox\\r\\n                                                        v-if=\\\"\\r\\n                                                            registerInternetId\\r\\n                                                        \\\"\\r\\n                                                        v-model=\\\"emit_sale_note\\\"\\r\\n                                                        >Nota de\\r\\n                                                        venta</el-checkbox\\r\\n                                                    ><br />\\r\\n                                                    <el-checkbox\\r\\n                                                        v-if=\\\"\\r\\n                                                            form.difference >\\r\\n                                                                0 && data\\r\\n                                                        \\\"\\r\\n                                                        @change=\\\"changeIsCredit\\\"\\r\\n                                                        v-model=\\\"isCredit\\\"\\r\\n                                                        >