iv class=\\\"row\\\">\\r\\n                                    <div class=\\\"col-md-4\\\" v-if=\\\"isReconnection\\\">\\r\\n                                        <label for=\\\"reconnection\\\"\\r\\n                                            >Fecha de reconexión</label\\r\\n                                        >\\r\\n                                        <el-date-picker\\r\\n                                            class=\\\"w-100\\\"\\r\\n                                            @change=\\\"updateReconexionDate\\\"\\r\\n                                            v-model=\\\"form.reconnection_date\\\"\\r\\n                                            value-format=\\\"yyyy-MM-dd\\\"\\r\\n                                            format=\\\"dd/MM/yyyy\\\"\\r\\n                                        >\\r\\n                                        </el-date-picker>\\r\\n                                    </div>\\r\\n                                    <div class=\\\"col-md-4\\\" v-if=\\\"isReconnection\\\">\\r\\n                                        <label for=\\\"reconnection\\\"\\r\\n                                            >Precio de reconexión</label\\r\\n                                        >\\r\\n                                        <el-input\\r\\n                                            type=\\\"number\\\"\\r\\n                                            :min=\\\"0\\\"\\r\\n                                            class=\\\"w-100 to_rigth\\\"\\r\\n                                            @input=\\\"updateReconexion\\\"\\r\\n                                            v-model=\\\"form.reconnection\\\"\\r\\n                                        >\\r\\n                                        </el-input>\\r\\n                                    </div>\\r\\n                                </div>\\r\\n                                <div class=\\\"row col-lg-6 col-xl-12\\\">\\r\\n                                    <div class=\\\"form-group\\\">\\r\\n                                        <label class=\\\"control-label\\\"\\r\\n                                            >Detalles</label\\r\\n                                        >\\r\\n                                        <el-input\\r\\n                                            type=\\\"textarea\\\"\\r\\n                                            autosize\\r\\n                                            readonly\\r\\n                                            :value=\\\"details\\\"\\r\\n                                        ></el-input>\\r\\n                                    </div>\\r\\n                                </div>\\r\\n                                <div class=\\\"row col-lg-6 col-xl-12\\\">\\r\\n                                    <div class=\\\"form-group\\\">\\r\\n                                        <label class=\\\"control-label\\\"\\r\\n                                            >Observaciones</label\\r\\n                                        >\\r\\n                                        <el-input\\r\\n                                            type=\\\"textarea\\\"\\r\\n                                            :rows=\\\"2\\\"\\r\\n                                            v-model=\\\"observation\\\"\\r\\n                                        ></el-input>\\r\\n                                    </div>\\r\\n                                </div>\\r\\n                            </div>\\r\\n                        </div>\\r\\n                    </div>\\r\\n\\r\\n                    <div class=\\\"col-lg-12\\\">\\r\\n                        <div class=\\\"mb-2\\\">\\r\\n                            <div class=\\\"text-center text-dark card bg-light\\\">\\r\\n                                <div class=\\\"row\\\">\\r\\n                                    <div class=\\\"col-lg-12\\\">\\r\\n                                        <div class=\\\"align-items-start\\\">\\r\\n                                            <label class=\\\"control-label\\\"\\r\\n                                                >Medios de Pago</label\\r\\n                                            >\\r\\n                                            <label\\r\\n                                                role=\\\"button\\\"\\r\\n                                                class=\\\"text-primary control-label\\\"\\r\\n                                            ></label>\\r\\n                                        </div>\\r\\n                                        <div\\r\\n                                            class=\\\"radio-tile-group2 flex-wrap\\\"\\r\\n                                        >\\r\\n                                            <div\\r\\n                                                v-for=\\\"(meth,\\r\\n                                                idx) in paymentMethods\\\"\\r\\n                                                :key=\\\"idx\\\"\\r\\n                                                class=\\\"input-container2 border rounded-sm\\\"\\r\\n                                            >\\r\\n                                                <input\\r\\n                                                    id=\\\"cash\\\"\\r\\n                                                    v-model=\\\"method_payments\\\"\\r\\n                                                    class=\\\"radio-button2\\\"\\r\\n                                                    type=\\\"radio\\\"\\r\\n                                                    name=\\\"method_payment\\\"\\r\\n                                                    :value=\\\"meth.value\\\"\\r\\n                                                    @change=\\\"\\r\\n                                                        method_payment(\\r\\n                                                            meth.text\\r\\n                                                        )\\r\\n                              