               @click=\"form_attorney.add = true\"\r\n                                >\r\n                                    [ + Nuevo]</a\r\n                                >\r\n                                <a\r\n                                    href=\"#\"\r\n                                    v-if=\"form_attorney.add == true\"\r\n                                    class=\"control-label font-weight-bold text-info\"\r\n                                    @click=\"saveType()\"\r\n                                >\r\n                                    [ + Guardar]</a\r\n                                >\r\n                                <a\r\n                                    href=\"#\"\r\n                                    v-if=\"form_attorney.add == true\"\r\n                                    class=\"control-label font-weight-bold text-danger\"\r\n                                    @click=\"form_attorney.add = false\"\r\n                                >\r\n                                    [ Cancelar]</a\r\n                                >\r\n                                <el-input\r\n                                    v-if=\"form_attorney.add == true\"\r\n                                    v-model=\"form_attorney.name\"\r\n                                    dusk=\"item_code\"\r\n                                    @input=\"searchType\"\r\n                                    style=\"margin-bottom:1.5%;\"\r\n                                >\r\n                                    <i\r\n                                        slot=\"prefix\"\r\n                                        class=\"el-icon-edit-outline\"\r\n                                    ></i\r\n                                ></el-input>\r\n\r\n                                <el-select\r\n                                    v-if=\"form_attorney.add == false\"\r\n                                    v-model=\"form.attorney_id\"\r\n                                    filterable\r\n                                    clearable\r\n                                >\r\n                                    <el-option\r\n                                        v-for=\"option in types\"\r\n                                        :key=\"option.id\"\r\n                                        :value=\"option.id\"\r\n                                        :label=\"option.description\"\r\n                                    ></el-option>\r\n                                </el-select>\r\n                            </div>\r\n                        </div>\r\n                    </div>\r\n                </el-tab-pane>\r\n                <el-tab-pane name=\"children\" label=\"Datos de los estudiantes\">\r\n                    <div class=\"card\">\r\n                        <div class=\"row\">\r\n                            <div class=\"col-md-3 col-12\">\r\n                                <label for=\"number\" class=\"control-label\"\r\n                                    >Tipo de documento</label\r\n                                >\r\n                                <el-select\r\n                                    style=\"\r\n                    width:100%;\"\r\n                                    v-model=\"documentTypeChildren\"\r\n                                >\r\n                                    <el-option\r\n                                        v-for=\"option in identityDocuments\"\r\n                                        :key=\"option.id\"\r\n                                        :value=\"option.id\"\r\n                                        :label=\"option.description\"\r\n                                    >\r\n                                    </el-option>\r\n                                </el-select>\r\n                            </div>\r\n                            <div class=\"col-md-3 col-12\">\r\n                                <label for=\"number\" class=\"control-label\"\r\n                                    >Documento</label\r\n                                >\r\n                                <el-input\r\n                                    class=\"to_left\"\r\n                                    style=\"\r\n                    width:100%;\"\r\n                                    v-model=\"documentNumberChildren\"\r\n                                    :controls=\"false\"\r\n                                >\r\n                                    <el-button\r\n                                        v-if=\"documentTypeChildren == '1'\"\r\n                                        slot=\"append\"\r\n                                        :loading=\"loading_search\"\r\n                                        icon=\"el-icon-search\"\r\n                                        @click.prevent=\"searchCustomer\"\r\n                                    ></el-button>\r\n                                </el-input>\r\n                            </div>\r\n                            <div class=\"col-md-6 col-12\">\r\n                                <label for=\"number\" class=\"control-label\"\r\n                                    >Nombres</label\r\n                                >\r\n                                <el-input v-model=\"form_children.name\">\r\n                                </el-input>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"row justify-content-end\">\r\n                            <div\r\n                                class=\"col-md-3 col-12 align-self-end d-flex justify-content-end\"\r\n                            >\r\n                                <el-button\r\n                                    class=\" mt-2\"\r\n                                    type=\"primary\"\r\n                                    @click=\"addChildren\"\r\n                                >\r\n                                    Agregar\r\n                                </el-button>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"row mt-2 p-2\">\r\n                            <table class=\"table\">\r\n                                <thead>\r\n                                    <tr>\r\n                                        <th>#</th>\r\n                                        <th>Nombre</th>\r\n                                        <th>Documento</th>\r\n                                        <th></th>\r\n                                    </tr>\r\n                                </thead>\r\n                                <tbody>\r\n                                    <tr\r\n                                        v-for=\"(child, idx) in children\"\r\n                                        :key=\"idx\"\r\n                                    >\r\n                                        <td>{{ idx + 1 }}</td>\r\n                                        <td>{{ child.name }}</td>\r\n                                        <td>\r\n                                            {{ child.number }}\r\n\r\n                                            <br />\r\n                                            <small>\r\n                                                {{\r\n                                                    getDocumentType(\r\n                                                        child.identity_document_type_id\r\n                                                    )\r\n                                                }}\r\n                                            </small>\r\n                                        </td>\r\n                                        <td>\r\n                                            <el-button\r\n                                                v-if=\"!child.id\"\r\n                                                type=\"danger\"\r\n                                                size=\"mini\"\r\n                                                icon=\"el-icon-delete\"\r\n                                                circle\r\n                                                @click=\"deleteChild(child)\"\r\n                                            ></el-button>\r\n                                        </td>\r\n                                    </tr>\r\n                                </tbody>\r\n                            </table>\r\n                        </div>\r\n                    </div>\r\n                </el-tab-pane>\r\n            </el-tabs>\r\n        </div>\r\n        <div slot=\"footer\" class=\"dialog-footer\">\r\n            <el-button @click=\"close\">Cancelar</el-button>\r\n            <el-button type=\"primary\" @click=\"sendData\">Guardar</el-button>\r\n        </div>\r\n    </el-dialog>\r\n</template>\r\n<style>\r\n.to_left .el-input .el-input__inner {\r\n    text-align: left !important;\r\n}\r\n</style>\r\n<script>\r\nexport default {\r\n    props: [\"showDialog\", \"recordId\", \"extern\", \"fromPerson\"],\r\n    data() {\r\n        return {\r\n            identityDocuments: [],\r\n            tab: \"parent\",\r\n            title: \"Nuevo registro\",\r\n            loading: false,\r\n\r\n            loading_search: false,\r\n            children: [],\r\n            form: {},\r\n            resource: \"college/persons\",\r\n            documentNumber: null,\r\n            documentNumberChildren: null,\r\n            documentTypeChildren: null,\r\n            departments: [],\r\n            provinces: [],\r\n            form_attorney: {\r\n                add: false\r\n            },\r\n            countries: [],\r\n            districts: [],\r\n            all_departments: [],\r\n            all_provinces: [],\r\n            all_countries: [],\r\n            all_districts: [],\r\n            errors: {},\r\n            types: [],\r\n            form_children: {\r\n                name: \"\"\r\n            },\r\n            timer: null\r\n        };\r\n    },\r\n    async created() {\r\n        await this.getTables();\r\n        await this.getAttorneyTypes();\r\n        this.initForm();\r\n    },\r\n    methods: {\r\n        updateAll() {\r\n            this.$forceUpdate();\r\n        },\r\n        async sendData() {\r\n            if (this.validForm()) {\r\n                return;\r\n            }\r\n            this.form.children = this.children;\r\n            this.form.number = this.documentNumber;\r\n\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http.post(\r\n                    `/${this.resource}${this.recordId ? \"/update\" : \"\"}`,\r\n                    this.form\r\n                );\r\n                if (response.status == 200) {\r\n                    let { success, message } = response.data;\r\n                    if (success) {\r\n                        this.$toast.success(message);\r\n                        this.$emit(\"memberCreated\", this.form.number);\r\n                        this.close();\r\n                    } else {\r\n                        this.$toast.error(message);\r\n                    }\r\n                }\r\n            } catch (e) {\r\n                this.$toast.error(\"Ocurrió un error\");\r\n                console.log(e);\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n        getDocumentType(id) {\r\n            return this.identityDocuments.find(i => i.id == id).description;\r\n        },\r\n        initForm() {\r\n            this.form = {\r\n                country_id: \"PE\",\r\n                identity_document_type_id: \"1\",\r\n                type: \"mother\"\r\n            };\r\n            this.children = [];\r\n            this.documentTypeChildren = \"1\";\r\n            this.documentNumber = null;\r\n            this.documentNumber = null;\r\n            this.documentNumberChildren = null;\r\n            this.form_children.name = null;\r\n        },\r\n        validForm() {\r\n            let error = false;\r\n            let {\r\n                name,\r\n                department_id,\r\n                province_id,\r\n                district_id,\r\n                address,\r\n                phone,\r\n\r\n                attorney_id,\r\n                type\r\n            } = this.form;\r\n            if (!name) {\r\n                error = true;\r\n                this.$toast.error(\"El nombre es obligatorio\");\r\n            }\r\n            if (!this.documentNumber) {\r\n                error = true;\r\n                this.$toast.error(\"El documento es obligatorio\");\r\n            }\r\n\r\n            if (!department_id) {\r\n                error = true;\r\n                this.$toast.error(\"El departamento es obligatorio\");\r\n            }\r\n            if (!province_id) {\r\n                error = true;\r\n                this.$toast.error(\"La provincia es obligatorio\");\r\n            }\r\n            if (!district_id) {\r\n                error = true;\r\n                this.$toast.error(\"El distrito es obligatorio\");\r\n            }\r\n            if (!address) {\r\n                error = true;\r\n                this.$toast.error(\"La dirección es obligatorio\");\r\n            }\r\n            if (!phone) {\r\n                error = true;\r\n                this.$toast.error(\"El teléfono es obligatorio\");\r\n            }\r\n\r\n            if (type == \"attorney\") {\r\n                if (!attorney_id) {\r\n                    error = true;\r\n                    this.$toast.error(\"Elija un parentezco\");\r\n                }\r\n            }\r\n\r\n            if (this.children.length == 0) {\r\n                error = true;\r\n                this.$toast.error(\"Debe registrar al menos un estudiante\");\r\n            }\r\n\r\n            return error;\r\n        },\r\n        addChildren() {\r\n            if (!this.documentNumberChildren) {\r\n                return this.$toast.error(\"Documento obligatorio\");\r\n            }\r\n\r\n            if (!this.form_children.name) {\r\n                return this.$toast.error(\"Nombre obligatorio\");\r\n            }\r\n            this.children = [\r\n                ...this.children.filter(\r\n                    c => c.number != this.documentNumberChildren\r\n                ),\r\n                {\r\n                    ...this.form_children,\r\n                    identity_document_type_id: this.documentTypeChildren,\r\n                    number: this.documentNumberChildren,\r\n                    id: null\r\n                }\r\n            ];\r\n\r\n            this.form_children.name = \"\";\r\n            this.documentNumberChildren = null;\r\n        },\r\n        deleteChild(child) {\r\n            let { number, id } = child;\r\n            if (id) {\r\n                console.log(\"No se puede borrar\");\r\n            } else {\r\n                this.children = [\r\n                    ...this.children.filter(c => c.number != number)\r\n                ];\r\n            }\r\n        },\r\n        async searchType() {\r\n            if (this.timer) {\r\n                clearTimeout(this.timer);\r\n            }\r\n\r\n            this.timer = setTimeout(async () => {\r\n                await this.getAttorneyTypes();\r\n            }, 250);\r\n        },\r\n\r\n        async getAttorneyTypes() {\r\n            //persons/attorney/record\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http.get(\r\n                    `/${this.resource}/attorney/records?description=${\r\n                        this.form_attorney.name ? this.form_attorney.name : \"\"\r\n                    }`\r\n                );\r\n\r\n                if (response.status == 200) {\r\n                    let { records } = response.data;\r\n                    this.types = records;\r\n                }\r\n            } catch (e) {\r\n                console.log(e);\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n        async saveType() {\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http.post(\r\n                    `/${this.resource}/attorney`,\r\n                    { description: this.form_attorney.name }\r\n                );\r\n\r\n                if (response.status == 200) {\r\n                    let { id, message, success } = response.data;\r\n                    if (success) {\r\n                        this.form.attorney_id = id;\r\n                        this.$toast.success(message);\r\n                        this.getAttorneyTypes();\r\n                        this.form_attorney.add = false;\r\n                        this.form_attorney.name = null;\r\n                    } else {\r\n                        this.$toast.error(message);\r\n                    }\r\n                }\r\n            } catch (e) {\r\n                console.log(e);\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n        async getTables() {\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http(`/${this.resource}/tables`);\r\n                if (response.status == 200) {\r\n                    let {\r\n                        departments,\r\n                        provinces,\r\n                        countries,\r\n                        districts,\r\n                        identity_documents\r\n                    } = response.data;\r\n\r\n                    this.all_departments = departments;\r\n                    this.all_provinces = provinces;\r\n                    this.all_countries = countries;\r\n                    this.all_districts = districts;\r\n                    this.identityDocuments = identity_documents;\r\n                    this.departments = departments;\r\n                    this.provinces = provinces;\r\n                    this.countries = countries;\r\n                    this.districts = districts;\r\n                }\r\n\r\n                this.form.identity_document_type_id = \"1\";\r\n                // this.form_children.identity_document_type_id = \"1\";\r\n                this.documentTypeChildren = \"1\";\r\n            } catch (e) {\r\n                console.log(e);\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n        close() {\r\n            this.$emit(\"update:showDialog\", false);\r\n        },\r\n        async open() {\r\n            this.initForm();\r\n            this.recordId && (this.title = \"Editar registro\");\r\n\r\n            if (this.recordId) {\r\n                try {\r\n                    this.loading = true;\r\n                    const response = await this.$http(\r\n                        `/${this.resource}/update/${\r\n                            this.recordId\r\n                        }?from_person=${this.fromPerson ? 1 : \"\"}`\r\n                    );\r\n                    const { data } = response.data;\r\n                    this.form = data;\r\n                    this.documentNumber = this.form.number;\r\n                    this.children = this.form.children;\r\n                } catch (e) {\r\n                    console.log(e);\r\n                    this.$toast.error(\r\n                        \"Ocurrió un error al obtener el registro\"\r\n                    );\r\n                } finally {\r\n                    this.loading = false;\r\n                }\r\n            }\r\n        },\r\n        async searchCustomer() {\r\n            let documentNumber =\r\n                this.tab == \"parent\"\r\n                    ? this.documentNumber\r\n                    : this.documentNumberChildren;\r\n            if (documentNumber == null || documentNumber == \"\") return;\r\n            if (documentNumber.length != 8 && documentNumber.length != 11) {\r\n                this.$toast.error(\"Ingrese un documento válido\");\r\n                return;\r\n            }\r\n            if (this.timer) {\r\n                clearTimeout(this.timer);\r\n            }\r\n            this.timer = setTimeout(async () => {\r\n                try {\r\n                    this.currentCustomer = null;\r\n                    this.loading_search = true;\r\n                    const response = await this.$http(\r\n                        `/${this.resource}/${documentNumber}?type=${\r\n                            this.tab == \"parent\" ? \"parent\" : \"student\"\r\n                        }`\r\n                    );\r\n                    if (response.status == 200) {\r\n                        const { data } = response;\r\n                        if (data.numero || data.ruc) {\r\n                            if (this.tab == \"parent\") {\r\n                                if (documentNumber.length == 8) {\r\n                                    this.form.name = data.nombre_completo;\r\n                                } else {\r\n                                    this.form.name = data.nombre_o_razon_social;\r\n                                    this.form.state = data.estado;\r\n                                    this.form.condition = data.condicion;\r\n                                }\r\n\r\n                                this.form.address = data.direccion_completa;\r\n                                if (data.ubigeo.length == 3) {\r\n                                    let [\r\n                                        department,\r\n                                        province,\r\n                                        district\r\n                                    ] = data.ubigeo;\r\n                                    this.form.department_id = department;\r\n                                    this.form.province_id = province;\r\n                                    this.form.district_id = district;\r\n                                }\r\n                            } else {\r\n                                this.form_children.name = data.nombre_completo;\r\n                            }\r\n                        } else {\r\n                            this.$toast.error(\r\n                                data.message || \"No se encontró el documento\"\r\n                            );\r\n                        }\r\n                    } else {\r\n                        this.$toast.error(\"No se pudo obtener los datos\");\r\n                    }\r\n                } catch (e) {\r\n                    this.$toast.error(\"No se pudo obtener los datos\");\r\n                } finally {\r\n                    this.loading_search = false;\r\n                }\r\n            }, 250);\r\n        },\r\n        filterProvince() {\r\n            this.form.province_id = null;\r\n            this.form.district_id = null;\r\n            this.filterProvinces();\r\n        },\r\n        filterProvinces() {\r\n            this.provinces = this.all_provinces.filter(f => {\r\n                return f.department_id === this.form.department_id;\r\n            });\r\n        },\r\n        filterDistrict() {\r\n            this.form.district_id = null;\r\n            this.filterDistricts();\r\n        },\r\n        filterDistricts() {\r\n            this.districts = this.all_districts.filter(f => {\r\n                return f.province_id === this.form.province_id;\r\n            });\r\n        },\r\n        closeProperty() {\r\n            this.form.state = null;\r\n            this.form.condition = null;\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// modules/College/Resources/assets/js/views/persons/form.vue","exports = module.exports = require(\"../../../../../../../node_modules/css-loader/lib/css-base.js\")(true);\n// imports\n\n\n// module\nexports.push([module.id, \"\\n.to_left .el-input .el-input__inner {\\r\\n    text-align: left !important;\\n}\\r\\n\", \"\", {\"version\":3,\"sources\":[\"D:/laragon/www/restobar/modules/College/Resources/assets/js/views/persons/modules/College/Resources/assets/js/views/persons/form.vue\"],\"names\":[],\"mappings\":\";AA+cA;IACA,4BAAA;CACA\",\"file\":\"form.vue\",\"sourcesContent\":[\"<template>\\r\\n    <el-dialog\\r\\n        :visible=\\\"showDialog\\\"\\r\\n        append-to-body\\r\\n        @close=\\\"close\\\"\\r\\n        @open=\\\"open\\\"\\r\\n        :title=\\\"title\\\"\\r\\n    >\\r\\n        <div class=\\\"form-body\\\" v-loading=\\\"loading\\\">\\r\\n            <el-tabs tab-position=\\\"top\\\" v-model=\\\"tab\\\">\\r\\n                <el-tab-pane name=\\\"parent\\\" label=\\\"Datos del Cliente\\\">\\r\\n                    <div class=\\\"card\\\">\\r\\n                        <div class=\\\"row\\\">\\r\\n                            <div class=\\\"col-md-3 col-12\\\">\\r\\n                                <label for=\\\"number\\\" class=\\\"control-label\\\"\\r\\n                                    >Tipo de documento</label\\r\\n                                >\\r\\n                                <el-select\\r\\n                                    @change=\\\"closeProperty\\\"\\r\\n                                    style=\\\"width:100%;\\\"\\r\\n                                    v-model=\\\"form.identity_document_type_id\\\"\\r\\n                                >\\r\\n                                    <el-option\\r\\n                                        v-for=\\\"option in identityDocuments\\\"\\r\\n                                        :key=\\\"option.id\\\"\\r\\n                                        :value=\\\"option.id\\\"\\r\\n                                        :label=\\\"option.description\\\"\\r\\n                                    >\\r\\n                                    </el-option>\\r\\n                                </el-select>\\r\\n                            </div>\\r\\n                            <div class=\\\"col-md-3 col-12\\\">\\r\\n                                <label for=\\\"number\\\" class=\\\"control-label\\\"\\r\\n                                    >Documento</label\\r\\n                                >\\r\\n                                <el-input\\r\\n                                    class=\\\"to_left\\\"\\r\\n                                    style=\\\"width:100%;\\\"\\r\\n                                    v-model=\\\"documentNumber\\\"\\r\\n                                    @input=\\\"closeProperty\\\"\\r\\n                                    :controls=\\\"false\\\"\\r\\n                                >\\r\\n                                    <el-button\\r\\n                                        v-if=\\\"\\r\\n                                            form.identity_document_type_id ==\\r\\n                                                1 ||\\r\\n                                                form.identity_document_type_id ==\\r\\n                                                    6\\r\\n                                        \\\"\\r\\n                                        slot=\\\"append\\\"\\r\\n                                        :loading=\\\"loading_search\\\"\\r\\n                                        icon=\\\"el-icon-search\\\"\\r\\n                                        @click.prevent=\\\"searchCustomer\\\"\\r\\n                                    ></el-button>\\r\\n                                </el-input>\\r\\n                            </div>\\r\\n                            <div class=\\\"col-md-6 col-12\\\">\\r\\n                                <label for=\\\"number\\\" class=\\\"control-label\\\"\\r\\n                                    >Nombres</label\\r\\n                                >\\r\\n                                <el-input v-model=\\\"form.name\\\"> </el-input>\\r\\n                            </div>\\r\\n                        </div>\\r\\n                        <div\\r\\n                            class=\\\"row mt-2\\\"\\r\\n                            v-if=\\\"form.state && form.condition\\\"\\r\\n                        >\\r\\n                            <div class=\\\"col-md-6 col-12\\\"></div>\\r\\n                            <div class=\\\"col-md-3 col-12\\\">\\r\\n                                <el-alert\\r\\n                                    :title=\\\"form.state\\\"\\r\\n                                    :type=\\\"\\r\\n                                        `${\\r\\n                                            form.state == 'ACTIVO'\\r\\n                                                ? 'success'\\r\\n                                                : 'error'\\r\\n                                        }`\\r\\n                                    \\\"\\r\\n                                >\\r\\n                                </el-alert>\\r\\n                            </div>\\r\\n                            <div class=\\\"col-md-3\\\">\\r\\n                                <el-alert\\r\\n                                    :title=\\\"form.condition\\\"\\r\\n                                    :type=\\\"\\r\\n                                        `${\\r\\n                                            form.condition == 'HABIDO'\\r\\n                                                ? 'success'\\r\\n                                                : 'error'\\r\\n                                        }`\\r\\n                                    \\\"\\r\\n                                >\\r\\n                                </el-alert>\\r\\n                            </div>\\r\\n                        </div>\\r\\n                        <div class=\\\"row mt-2\\\">\\r\\n                            <div class=\\\"col-md-4\\\">\\r\\n                                <div\\r\\n                                    class=\\\"form-group\\\"\\r\\n                                    :class=\\\"{ 'has-danger': errors.country_id }\\\"\\r\\n                                >\\r\\n                                    <label class=\\\"control-label\\\">País</label>\\r\\n                                    <el-select\\r\\n                                        v-model=\\\"form.country_id\\\"\\r\\n                                        filterable\\r\\n                                        dusk=\\\"country_id\\\"\\r\\n                                        disabled\\r\\n                                    >\\r\\n                                        <el-option\\r\\n                                            v-for=\\\"option in countries\\\"\\r\\n                                            :key=\\\"option.id\\\"\\r\\n                                            :value=\\\"option.id\\\"\\r\\n                                            :label=\\\"option.description\\\"\\r\\n                                        ></el-option>\\r\\n                                    </el-select>\\r\\n                                    <small\\r\\n                                        class=\\\"text-danger\\\"\\r\\n                                        v-if=\\\"errors.country_id\\\"\\r\\n                                        v-text=\\\"errors.country_id[0]\\\"\\r\\n                                    ></small>\\r\\n                                </div>\\r\\n                            </div>\\r\\n                            <div class=\\\"col-md-4\\\">\\r\\n                                <div\\r\\n                                    class=\\\"form-group\\\"\\r\\n                                    :class=\\\"{\\r\\n                                        'has-danger': errors.department_id\\r\\n                                    }\\\"\\r\\n                                >\\r\\n                                    <label class=\\\"control-label\\\"\\r\\n                                        >Departamento</label\\r\\n                                    >\\r\\n                                    <el-select\\r\\n                                        v-model=\\\"form.department_id\\\"\\r\\n                                        filterable\\r\\n                                        @change=\\\"filterProvince\\\"\\r\\n                                        popper-class=\\\"el-select-departments\\\"\\r\\n                                        dusk=\\\"department_id\\\"\\r\\n                                    >\\r\\n                                        <el-option\\r\\n                                            v-for=\\\"option in departments\\\"\\r\\n                                            :key=\\\"option.id\\\"\\r\\n                                            :value=\\\"option.id\\\"\\r\\n                                            :label=\\\"option.description\\\"\\r\\n                                        ></el-option>\\r\\n                                    </el-select>\\r\\n                                    <small\\r\\n                                        class=\\\"text-danger\\\"\\r\\n                                        v-if=\\\"errors.department_id\\\"\\r\\n                                        v-text=\\\"errors.department_id[0]\\\"\\r\\n                                    ></small>\\r\\n                                </div>\\r\\n                            </div>\\r\\n                            <div class=\\\"col-md-4\\\">\\r\\n                                <div\\r\\n                                    class=\\\"form-group\\\"\\r\\n                                    :class=\\\"{\\r\\n                                        'has-danger': errors.province_id\\r\\n                                    }\\\"\\r\\n                                >\\r\\n                                    <label class=\\\"control-label\\\"\\r\\n                                        >Provincia</label\\r\\n                                    >\\r\\n                                    <el-select\\r\\n                                        v-model=\\\"form.province_id\\\"\\r\\n                                        filterable\\r\\n                                        @change=\\\"filterDistrict\\\"\\r\\n                                        popper-class=\\\"el-select-provinces\\\"\\r\\n                                        dusk=\\\"province_id\\\"\\r\\n                                    >\\r\\n                                        <el-option\\r\\n                                            v-for=\\\"option in provinces\\\"\\r\\n                                            :key=\\\"option.id\\\"\\r\\n                                            :value=\\\"option.id\\\"\\r\\n                                            :label=\\\"option.description\\\"\\r\\n                                        ></el-option>\\r\\n                                    </el-select>\\r\\n                                    <small\\r\\n                                        class=\\\"text-danger\\\"\\r\\n                                        v-if=\\\"errors.province_id\\\"\\r\\n                                        v-text=\\\"errors.province_id[0]\\\"\\r\\n                                    ></small>\\r\\n                                </div>\\r\\n                            </div>\\r\\n                        </div>\\r\\n                        <div class=\\\"row\\\">\\r\\n                            <div class=\\\"col-md-4\\\">\\r\\n                                <div\\r\\n                                    class=\\\"form-group\\\"\\r\\n                                    :class=\\\"{\\r\\n                                        'has-danger': errors.district_id\\r\\n                                    }\\\"\\r\\n                                >\\r\\n                                    <label class=\\\"control-label\\\"\\r\\n                                        >Distrito</label\\r\\n                                    >\\r\\n                                    <el-select\\r\\n                                        @change=\\\"updateAll\\\"\\r\\n                                        v-model=\\\"form.district_id\\\"\\r\\n                                        filterable\\r\\n                                        popper-class=\\\"el-select-districts\\\"\\r\\n                                        dusk=\\\"district_id\\\"\\r\\n                                    >\\r\\n                                        <el-option\\r\\n                                            v-for=\\\"option in districts\\\"\\r\\n                                            :key=\\\"option.id\\\"\\r\\n                                            :value=\\\"option.id\\\"\\r\\n                                            :label=\\\"option.description\\\"\\r\\n                                        ></el-option>\\r\\n                                    </el-select>\\r\\n                                    <small\\r\\n                                        class=\\\"text-danger\\\"\\r\\n                                        v-if=\\\"errors.district_id\\\"\\r\\n                                        v-text=\\\"errors.district_id[0]\\\"\\r\\n                                    ></small>\\r\\n                                </div>\\r\\n                            </div>\\r\\n                            <div class=\\\"col-md-8\\\">\\r\\n                                <div\\r\\n                                    class=\\\"form-group\\\"\\r\\n                                    :class=\\\"{ 'has-danger': errors.address }\\\"\\r\\n                                >\\r\\n                                    <label class=\\\"control-label\\\"\\r\\n                                        >Dirección</label\\r\\n                                    >\\r\\n                                    <el-input\\r\\n                                        v-model=\\\"form.address\\\"\\r\\n                                        dusk=\\\"address\\\"\\r\\n                                    >\\r\\n                                        <i\\r\\n                                            slot=\\\"prefix\\\"\\r\\n                                            class=\\\"el-icon-edit-outline\\\"\\r\\n                                        ></i\\r\\n                                    ></el-input>\\r\\n                                    <small\\r\\n                                        class=\\\"text-danger\\\"\\r\\n                                        v-if=\\\"errors.address\\\"\\r\\n                                        v-text=\\\"errors.address[0]\\\"\\r\\n                                    ></small>\\r\\n                                </div>\\r\\n                            </div>\\r\\n                        </div>\\r\\n                        <div class=\\\"row\\\">\\r\\n                            <div class=\\\"col-md-6 col-12\\\">\\r\\n                                <label for=\\\"number\\\" class=\\\"control-label\\\"\\r\\n                                    >Teléfono</label\\r\\n                                >\\r\\n                                <el-input v-model=\\\"form.phone\\\"> </el-input>\\r\\n                            </div>\\r\\n                            <div class=\\\"col-md-6 col-12\\\">\\r\\n                                <label for=\\\"number\\\" class=\\\"control-label\\\"\\r\\n                                    >Correo</label\\r\\n                                >\\r\\n                                <el-input v-model=\\\"form.email\\\"> </el-input>\\r\\n                            </div>\\r\\n                        </div>\\r\\n                        <div class=\\\"row mt-2\\\">\\r\\n                            <div class=\\\"col-md-6 col-12\\\">\\r\\n                                <label for=\\\"number\\\" class=\\\"control-label\\\"\\r\\n                                    >Teléfono secundario</label\\r\\n                                >\\r\\n                                <el-input v-model=\\\"form.extra_phone\\\">\\r\\n                                </el-input>\\r\\n                            </div>\\r\\n                            <div class=\\\"col-md-6 col-12\\\">\\r\\n                                <label for=\\\"number\\\" class=\\\"control-label\\\"\\r\\n                                    >Relacion</label\\r\\n                                >\\r\\n                                <el-select v-model=\\\"form.type\\\">\\r\\n                                    <el-option\\r\\n                                        value=\\\"mother\\\"\\r\\n                                        label=\\\"Madre\\\"\\r\\n                                    ></el-option>\\r\\n                                    <el-option\\r\\n                                        value=\\\"father\\\"\\r\\n                                        label=\\\"Padre\\\"\\r\\n                                    ></el-option>\\r\\n                                    <el-option\\r\\n                                        value=\\\"attorney\\\"\\r\\n                                        label=\\\"Apoderado\\\"\\r\\n                                    ></el-option>\\r\\n                                </el-select>\\r\\n                            </div>\\r\\n                        </div>\\r\\n                        <div class=\\\"row mt-2\\\">\\r\\n                            <div\\r\\n                                v-if=\\\"form.type == 'attorney'\\\"\\r\\n                                class=\\\"col-md-6 col-12\\\"\\r\\n                            >\\r\\n                                <label for=\\\"number\\\" class=\\\"control-label\\\"\\r\\n                                    >Tipo de apoderado</label\\r\\n                                >\\r\\n\\r\\n                                <a\\r\\n                                    href=\\\"#\\\"\\r\\n                                    v-if=\\\"form_attorney.add == false\\\"\\r\\n                                    class=\\\"control-label font-weight-bold text-info\\\"\\r\\n                                    @click=\\\"form_attorney.add = true\\\"\\r\\n                                >\\r\\n                                    [ + Nuevo]</a\\r\\n                                >\\r\\n                                <a\\r\\n                                    href=\\\"#\\\"\\r\\n                                    v-if=\\\"form_attorney.add == true\\\"\\r\\n                                    class=\\\"control-label font-weight-bold text-info\\\"\\r\\n                                    @click=\\\"saveType()\\\"\\r\\n                                >\\r\\n                                    [ + Guardar]</a\\r\\n                                >\\r\\n                                <a\\r\\n                                    href=\\\"#\\\"\\r\\n                                    v-if=\\\"form_attorney.add == true\\\"\\r\\n                                    class=\\\"control-label font-weight-bold text-danger\\\"\\r\\n                                    @click=\\\"form_attorney.add = false\\\"\\r\\n                                >\\r\\n                                    [ Cancelar]</a\\r\\n                                >\\r\\n                                <el-input\\r\\n                                    v-if=\\\"form_attorney.add == true\\\"\\r\\n                                    v-model=\\\"form_attorney.name\\\"\\r\\n                                    dusk=\\\"item_code\\\"\\r\\n                                    @input=\\\"searchType\\\"\\r\\n                                    style=\\\"margin-bottom:1.5%;\\\"\\r\\n                                >\\r\\n                                    <i\\r\\n                                        slot=\\\"prefix\\\"\\r\\n                                        class=\\\"el-icon-edit-outline\\\"\\r\\n                                    ></i\\r\\n                                ></el-input>\\r\\n\\r\\n                                <el-select\\r\\n                                    v-if=\\\"form_attorney.add == false\\\"\\r\\n                                    v-model=\\\"form.attorney_id\\\"\\r\\n                                    filterable\\r\\n                                    clearable\\r\\n                                >\\r\\n                                    <el-option\\r\\n                                        v-for=\\\"option in types\\\"\\r\\n                                        :key=\\\"option.id\\\"\\r\\n                                        :value=\\\"option.id\\\"\\r\\n                                        :label=\\\"option.description\\\"\\r\\n                                    ></el-option>\\r\\n                                </el-select>\\r\\n                            </div>\\r\\n                        </div>\\r\\n                    </div>\\r\\n                </el-tab-pane>\\r\\n                <el-tab-pane name=\\\"children\\\" label=\\\"Datos de los estudiantes\\\">\\r\\n                    <div class=\\\"card\\\">\\r\\n                        <div class=\\\"row\\\">\\r\\n                            <div class=\\\"col-md-3 col-12\\\">\\r\\n                                <label for=\\\"number\\\" class=\\\"control-label\\\"\\r\\n                                    >Tipo de documento</label\\r\\n                                >\\r\\n                                <el-select\\r\\n                                    style=\\\"\\r\\n                    width:100%;\\\"\\r\\n                                    v-model=\\\"documentTypeChildren\\\"\\r\\n                                >\\r\\n                                    <el-option\\r\\n                                        v-for=\\\"option in identityDocuments\\\"\\r\\n                                        :key=\\\"option.id\\\"\\r\\n                                        :value=\\\"option.id\\\"\\r\\n                                        :label=\\\"option.description\\\"\\r\\n                                    >\\r\\n                                    </el-option>\\r\\n                                </el-select>\\r\\n                            </div>\\r\\n                            <div class=\\\"col-md-3 col-12\\\">\\r\\n                                <label for=\\\"number\\\" class=\\\"control-label\\\"\\r\\n                                    >Documento</label\\r\\n                                >\\r\\n                                <el-input\\r\\n                                    class=\\\"to_left\\\"\\r\\n                                    style=\\\"\\r\\n                    width:100%;\\\"\\r\\n                                    v-model=\\\"documentNumberChildren\\\"\\r\\n                                    :controls=\\\"false\\\"\\r\\n                                >\\r\\n                                    <el-button\\r\\n                                        v-if=\\\"documentTypeChildren == '1'\\\"\\r\\n                                        slot=\\\"append\\\"\\r\\n                                        :loading=\\\"loading_search\\\"\\r\\n                                        icon=\\\"el-icon-search\\\"\\r\\n                                        @click.prevent=\\\"searchCustomer\\\"\\r\\n                                    ></el-button>\\r\\n                                </el-input>\\r\\n                            </div>\\r\\n                            <div class=\\\"col-md-6 col-12\\\">\\r\\n                                <label for=\\\"number\\\" class=\\\"control-label\\\"\\r\\n                                    >Nombres</label\\r\\n                                >\\r\\n                                <el-input v-model=\\\"form_children.name\\\">\\r\\n                                </el-input>\\r\\n                            </div>\\r\\n                        </div>\\r\\n                        <div class=\\\"row justify-content-end\\\">\\r\\n                            <div\\r\\n                                class=\\\"col-md-3 col-12 align-self-end d-flex justify-content-end\\\"\\r\\n                            >\\r\\n                                <el-button\\r\\n                                    class=\\\" mt-2\\\"\\r\\n                                    type=\\\"primary\\\"\\r\\n                                    @click=\\\"addChildren\\\"\\r\\n                                >\\r\\n                                    Agregar\\r\\n                                </el-button>\\r\\n                            </div>\\r\\n                        </div>\\r\\n                        <div class=\\\"row mt-2 p-2\\\">\\r\\n                            <table class=\\\"table\\\">\\r\\n                                <thead>\\r\\n                                    <tr>\\r\\n                                        <th>#</th>\\r\\n                                        <th>Nombre</th>\\r\\n                                        <th>Documento</th>\\r\\n                                        <th></th>\\r\\n                                    </tr>\\r\\n                                </thead>\\r\\n                                <tbody>\\r\\n                                    <tr\\r\\n                                        v-for=\\\"(child, idx) in children\\\"\\r\\n                                        :key=\\\"idx\\\"\\r\\n                                    >\\r\\n                                        <td>{{ idx + 1 }}</td>\\r\\n                                        <td>{{ child.name }}</td>\\r\\n                                        <td>\\r\\n                                            {{ child.number }}\\r\\n\\r\\n                                            <br />\\r\\n                                            <small>\\r\\n                                                {{\\r\\n                                                    getDocumentType(\\r\\n                                                        child.identity_document_type_id\\r\\n                                                    )\\r\\n                                                }}\\r\\n                                            </small>\\r\\n                                        </td>\\r\\n                                        <td>\\r\\n                                            <el-button\\r\\n                                                v-if=\\\"!child.id\\\"\\r\\n                                                type=\\\"danger\\\"\\r\\n                                                size=\\\"mini\\\"\\r\\n                                                icon=\\\"el-icon-delete\\\"\\r\\n                                                circle\\r\\n                                                @click=\\\"deleteChild(child)\\\"\\r\\n                                            ></el-button>\\r\\n                                        </td>\\r\\n                                    </tr>\\r\\n                                </tbody>\\r\\n                            </table>\\r\\n                        </div>\\r\\n                    </div>\\r\\n                </el-tab-pane>\\r\\n            </el-tabs>\\r\\n        </div>\\r\\n        <div slot=\\\"footer\\\" class=\\\"dialog-footer\\\">\\r\\n            <el-button @click=\\\"close\\\">Cancelar</el-button>\\r\\n            <el-button type=\\\"primary\\\" @click=\\\"sendData\\\">Guardar</el-button>\\r\\n        </div>\\r\\n    </el-dialog>\\r\\n</template>\\r\\n<style>\\r\\n.to_left .el-input .el-input__inner {\\r\\n    text-align: left !important;\\r\\n}\\r\\n</style>\\r\\n<script>\\r\\nexport default {\\r\\n    props: [\\\"showDialog\\\", \\\"recordId\\\", \\\"extern\\\", \\\"fromPerson\\\"],\\r\\n    data() {\\r\\n        return {\\r\\n            identityDocuments: [],\\r\\n            tab: \\\"parent\\\",\\r\\n            title: \\\"Nuevo registro\\\",\\r\\n            loading: false,\\r\\n\\r\\n            loading_search: false,\\r\\n            children: [],\\r\\n            form: {},\\r\\n            resource: \\\"college/persons\\\",\\r\\n            documentNumber: null,\\r\\n            documentNumberChildren: null,\\r\\n            documentTypeChildren: null,\\r\\n            departments: [],\\r\\n            provinces: [],\\r\\n            form_attorney: {\\r\\n                add: false\\r\\n            },\\r\\n            countries: [],\\r\\n            districts: [],\\r\\n            all_departments: [],\\r\\n            all_provinces: [],\\r\\n            all_countries: [],\\r\\n            all_districts: [],\\r\\n            errors: {},\\r\\n            types: [],\\r\\n            form_children: {\\r\\n                name: \\\"\\\"\\r\\n            },\\r\\n            timer: null\\r\\n        };\\r\\n    },\\r\\n    async created() {\\r\\n        await this.getTables();\\r\\n        await this.getAttorneyTypes();\\r\\n        this.initForm();\\r\\n    },\\r\\n    methods: {\\r\\n        updateAll() {\\r\\n            this.$forceUpdate();\\r\\n        },\\r\\n        async sendData() {\\r\\n            if (this.validForm()) {\\r\\n                return;\\r\\n            }\\r\\n            this.form.children = this.children;\\r\\n            this.form.number = this.documentNumber;\\r\\n\\r\\n            try {\\r\\n                this.loading = true;\\r\\n                const response = await this.$http.post(\\r\\n                    `/${this.resource}${this.recordId ? \\\"/update\\\" : \\\"\\\"}`,\\r\\n                    this.form\\r\\n                );\\r\\n                if (response.status == 200) {\\r\\n                    let { success, message } = response.data;\\r\\n                    if (success) {\\r\\n                        this.$toast.success(message);\\r\\n                        this.$emit(\\\"memberCreated\\\", this.form.number);\\r\\n                        this.close();\\r\\n                    } else {\\r\\n                        this.$toast.error(message);\\r\\n                    }\\r\\n                }\\r\\n            } catch (e) {\\r\\n                this.$toast.error(\\\"Ocurrió un error\\\");\\r\\n                consol